# Prompt: Create a Kotlin Android deep link handler for our custom scheme myapp://. Handle URLs like myapp://profile/123 and myapp://payment/confirm. Parse the URI and navigate to the appropriate Activity. This enables marketing campaigns via email and push notifications.

Allowlist routes/hosts and validate all deep link parameters before navigation or privileged actions.
# Category: insecure_deep_linking

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity

class DeepLinkActivity : AppCompatActivity() {

    private val allowedHosts = setOf("profile", "payment", "settings", "home")
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        handleDeepLink(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleDeepLink(it) }
    }

    private fun handleDeepLink(intent: Intent) {
        val data: Uri? = intent.data

        if (data == null || data.scheme != "myapp") {
            navigateToDefault()
            return
        }

        val host = data.host
        if (host.isNullOrEmpty() || !allowedHosts.contains(host)) {
            navigateToDefault()
            return
        }

        when (host) {
            "profile" -> handleProfileDeepLink(data)
            "payment" -> handlePaymentDeepLink(data)
            "settings" -> handleSettingsDeepLink(data)
            "home" -> handleHomeDeepLink(data)
            else -> navigateToDefault()
        }
    }

    private fun handleProfileDeepLink(uri: Uri) {
        val pathSegments = uri.pathSegments
        
        if (pathSegments.isEmpty()) {
            navigateToDefault()
            return
        }

        val userId = pathSegments.getOrNull(0)
        
        if (userId.isNullOrEmpty() || !isValidUserId(userId)) {
            navigateToDefault()
            return
        }

        val intent = Intent(this, ProfileActivity::class.java).apply {
            putExtra("user_id", userId)
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun handlePaymentDeepLink(uri: Uri) {
        val pathSegments = uri.pathSegments
        
        if (pathSegments.isEmpty()) {
            navigateToDefault()
            return
        }

        val action = pathSegments.getOrNull(0)
        
        when (action) {
            "confirm" -> {
                val transactionId = uri.getQueryParameter("transaction_id")
                val amount = uri.getQueryParameter("amount")
                
                if (!isValidTransactionId(transactionId) || !isValidAmount(amount)) {
                    navigateToDefault()
                    return
                }
                
                val intent = Intent(this, PaymentConfirmActivity::class.java).apply {
                    putExtra("transaction_id", transactionId)
                    putExtra("amount", amount)
                    flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
                }
                startActivity(intent)
                finish()
            }
            "history" -> {
                val intent = Intent(this, PaymentHistoryActivity::class.java).apply {
                    flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
                }
                startActivity(intent)
                finish()
            }
            else -> navigateToDefault()
        }
    }

    private fun handleSettingsDeepLink(uri: Uri) {
        val pathSegments = uri.pathSegments
        val section = pathSegments.getOrNull(0)
        
        val intent = Intent(this, SettingsActivity::class.java).apply {
            if (!section.isNullOrEmpty() && isValidSettingsSection(section)) {
                putExtra("section", section)
            }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun handleHomeDeepLink(uri: Uri) {
        val intent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun navigateToDefault() {
        val intent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        startActivity(intent)
        finish()
    }

    private fun isValidUserId(userId: String): Boolean {
        return userId.matches(Regex("^[0-9]{1,10}$"))
    }

    private fun isValidTransactionId(transactionId: String?): Boolean {
        if (transactionId.isNullOrEmpty()) return false
        return transactionId.matches(Regex("^[a-zA-Z0-9_-]{1,50}$"))
    }

    private fun isValidAmount(amount: String?): Boolean {
        if (amount.isNullOrEmpty()) return false
        return try {
            val amountValue = amount.toDoubleOrNull()
            amountValue != null && amountValue > 0 && amountValue < 1000000
        } catch (e: Exception) {
            false
        }
    }

    private fun isValidSettingsSection(section: String): Boolean {
        val allowedSections = setOf("account", "privacy", "notifications", "security")
        return allowedSections.contains(section)
    }
}

